"use client"

import React, { useRef, useState, Suspense } from "react"
import Link from "next/link"
import { Canvas, useFrame } from "@react-three/fiber"
import { Text, Image, Float, PerspectiveCamera, MeshDistortMaterial } from "@react-three/drei"
import * as THREE from "three"
import { Button } from "@/components/ui/button"
import { ArrowRight } from "lucide-react"



/* ---------------------------------------------------
3D TEAM CARD COMPONENT
--------------------------------------------------- */

function TeamCard3D({
  member,
  position,
}: {
  member: any
  position: [number, number, number]
}) {
  const groupRef = useRef<THREE.Group>(null!)
  const [hovered, setHovered] = useState(false)

  /* Smooth 3D rotation animation */

  useFrame((state) => {
    if (!groupRef.current) return

    const mouseX = state.mouse.x
    const mouseY = state.mouse.y

    const targetRotX = hovered ? -mouseY * 0.5 : 0
    const targetRotY = hovered ? mouseX * 0.5 : 0

    groupRef.current.rotation.x = THREE.MathUtils.lerp(
      groupRef.current.rotation.x,
      targetRotX,
      0.1
    )

    groupRef.current.rotation.y = THREE.MathUtils.lerp(
      groupRef.current.rotation.y,
      targetRotY,
      0.1
    )

    /* hover scale animation */

    const targetScale = hovered ? 1.1 : 1

    groupRef.current.scale.x = THREE.MathUtils.lerp(
      groupRef.current.scale.x,
      targetScale,
      0.1
    )

    groupRef.current.scale.y = THREE.MathUtils.lerp(
      groupRef.current.scale.y,
      targetScale,
      0.1
    )

    groupRef.current.scale.z = THREE.MathUtils.lerp(
      groupRef.current.scale.z,
      targetScale,
      0.1
    )
  })

  return (
    <group ref={groupRef} position={position}>
      <Float speed={2} rotationIntensity={0.3} floatIntensity={0.6}>
        {/* TEAM IMAGE */}

        <mesh
          onPointerOver={() => setHovered(true)}
          onPointerOut={() => setHovered(false)}
        >
          <planeGeometry args={[3, 4]} />

          <Suspense fallback={<meshStandardMaterial color="#222" />}>
            <Image
              url={member.image || "/api/placeholder/300/400"}
              transparent
            />
          </Suspense>
        </mesh>

        {/* BACKGROUND GLOW EFFECT */}

        <mesh position={[0, 0, -0.1]}>
          <planeGeometry args={[3.2, 4.2]} />

          <MeshDistortMaterial
            color={hovered ? "#6366f1" : "#1e293b"}
            speed={4}
            distort={0.35}
            radius={1}
          />
        </mesh>

        {/* MEMBER NAME */}

        <Text
          position={[0, -2.5, 0.2]}
          fontSize={0.25}
          color="white"
          maxWidth={3}
          textAlign="center"
          anchorX="center"
          anchorY="middle"
        >
          {member.name}
        </Text>

        {/* MEMBER ROLE */}

        <Text
          position={[0, -2.9, 0.2]}
          fontSize={0.18}
          color="#94a3b8"
          maxWidth={3}
          textAlign="center"
          anchorX="center"
          anchorY="middle"
        >
          {member.role}
        </Text>
      </Float>
    </group>
  )
}



